import{c as t,Q as n,j as i,m as o}from"./chunks/framework.D5MFXpji.js";const g=JSON.parse('{"title":"Environment","description":"","frontmatter":{"title":"Environment","order":6},"headers":[],"relativePath":"en/environment/index.md","filePath":"en/environment/index.md","lastUpdated":1781136698000}'),a={name:"en/environment/index.md"};function s(r,e,l,c,h,d){return n(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h1><p>Now that shadows have been applied and a sense of three-dimensionality has been formed, it&#39;s time to add infinite backgrounds and photorealistic light information. RedGPU provides the following features to maximize the realism of 3D scenes:</p><ul><li><strong>Skybox</strong>: Represents the infinite background of the scene.</li><li><strong>Image-Based Lighting (IBL)</strong>: Uses surrounding environment images as light sources for physical reflections and global lighting.</li><li><strong>SkyAtmosphere</strong>: Simulates real-time physically-based atmospheric scattering.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>Tone Mapping</strong>, which fine-tunes the final color scheme of the screen, will be covered in detail in the later post-effects section.</p></div><h2 id="main-learning-topics" tabindex="-1">Main Learning Topics <a class="header-anchor" href="#main-learning-topics" aria-label="Permalink to &quot;Main Learning Topics&quot;">​</a></h2><ul><li><strong><a href="./skybox.html">SkyBox</a></strong>: Fills the scene background with 360-degree textures to provide a vast sense of space.</li><li><strong><a href="./ibl.html">IBL</a></strong>: Analyzes light information from the surrounding environment to apply realistic reflection and lighting to objects.</li><li><strong><a href="./skyatmosphere.html">SkyAtmosphere</a></strong>: Provides a real-time, physically-based atmospheric scattering simulation to add dynamic sky and atmosphere scattering effects to the scene.</li></ul><div class="info custom-block"><p class="custom-block-title">[Learning Guide]</p><p>First, we will look at <strong>SkyBox</strong>, which defines the background of the space, then <strong>IBL</strong>, where the background acts as actual lighting on objects, and finally <strong>SkyAtmosphere</strong> for real-time physical simulation of atmospheric scattering.</p></div><hr><p><a href="./skybox.html">Next Step: Learn SkyBox</a></p>',9)])])}const p=t(a,[["render",s]]);export{g as __pageData,p as default};
